@using sv_db5e1fb5c3c64e10b5f053ebe2a4e43a

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="small text-muted">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft" disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight" disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@using sv_db5e1fb5c3c64e10b5f053ebe2a4e43a

<div class="card border-primary mb-2">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-primary btn-sm" @onclick="HandleSave" disabled="@isSaving">
                @(isSaving ? "Saving..." : "Save")
            </button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="OnCancel" disabled="@isSaving">Cancel</button>
        </div>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="text-danger small mt-1">@errorMessage</div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? errorMessage;

    private async Task HandleSave()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(title))
        {
            errorMessage = "Title is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(assignee))
        {
            errorMessage = "Assignee is required.";
            return;
        }

        isSaving = true;
        try
        {
            await OnSave.InvokeAsync(
                new TaskItem(0, title.Trim(), assignee.Trim(), priority, dueDate, Status));
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }
}

@using sv_db5e1fb5c3c64e10b5f053ebe2a4e43a

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="HasLeftColumn"
                          ShowMoveRight="HasRightColumn"
                          IsMoving="movingTaskId == task.Id"
                          OnMoveLeft="() => HandleMoveLeft(task)"
                          OnMoveRight="() => HandleMoveRight(task)" />
            }

            @if (showAddForm)
            {
                <AddTaskForm Status="@Status"
                             OnSave="HandleTaskCreated"
                             OnCancel="() => showAddForm = false" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showAddForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool HasLeftColumn { get; set; }
    [Parameter] public bool HasRightColumn { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter] public string? LeftStatus { get; set; }
    [Parameter] public string? RightStatus { get; set; }

    private bool showAddForm;
    private int? movingTaskId;

    private async Task HandleMoveLeft(TaskItem task)
    {
        if (LeftStatus is null) return;
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task.Id, LeftStatus));
        movingTaskId = null;
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        if (RightStatus is null) return;
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task.Id, RightStatus));
        movingTaskId = null;
    }

    private async Task HandleTaskCreated(TaskItem task)
    {
        await OnTaskCreated.InvokeAsync(task);
        showAddForm = false;
    }
}

